mapper.select:
select * from sys_message where db_status = 1
and title like concat('%', #{title}, '%')
and content like concat('%', #{content}, '%')
and state = #{state}
and to_id = #{toId}
and from_id = #{fromId}
and no_state != #{noState}
order by id desc

select * from sys_message where db_status = 1
and state = #{state}
and to_id = #{userId}
order by create_time desc
